hooks.command:
python3 -c "
import subprocess, sys, json

def run(cmd):
    r = subprocess.run(cmd, shell=True, capture_output=True, text=True)
    return r.stdout.strip()

branch    = run('git branch --show-current')
commits   = run('git log --oneline -3')
unstaged  = run('git diff --name-only')
staged    = run('git diff --cached --name-only')
focus     = ''
try:
    with open('CLAUDE.md') as f:
        for line in f:
            if 'Current focus' in line or 'Active Development' in line:
                focus = line.strip()
                break
except:
    pass

print('--- COMPACTION CONTEXT ---')
print(f'Branch: {branch}')
print(f'Last 3 commits:\n{commits}')
if unstaged:
    print(f'Unstaged changes: {unstaged}')
if staged:
    print(f'Staged changes: {staged}')
if not unstaged and not staged:
    print('Working tree: clean')
if focus:
    print(f'Active focus: {focus}')
print('--------------------------')
"
